impl<S: Socket> Write for StdSocket<S> {
    fn write(&mut self, buf: &[u8]) -> io::Result<usize> {
        self.wants_write = true;
        let written = self.socket.try_write(buf)?;
        self.wants_write = false;
        Ok(written)
    }

    fn flush(&mut self) -> io::Result<()> {
        // NOTE: TCP sockets and unix sockets are both no-ops for flushes
        Ok(())
    }
}

impl Drop for ConnectionHandle {
    fn drop(&mut self) {
        unsafe {
            // https://sqlite.org/c3ref/close.html
            let status = sqlite3_close(self.0.as_ptr());
            if status != SQLITE_OK {
                // this should *only* happen due to an internal bug in SQLite where we left
                // SQLite handles open
                panic!("{}", SqliteError::new(self.0.as_ptr()));
            }
        }
    }
}

impl FrontendMessage for CopyFail {
    const FORMAT: FrontendMessageFormat = FrontendMessageFormat::CopyFail;

    #[inline(always)]
    fn body_size_hint(&self) -> Saturating<usize> {
        Saturating(self.message.len())
    }

    #[inline(always)]
    fn encode_body(&self, buf: &mut Vec<u8>) -> std::result::Result<(), Error> {
        buf.put_str_nul(&self.message);
        Ok(())
    }
}

